let usernameValid = false;

async function checkUsername() {
    const username = document.getElementById("username").value;
    const msg = document.getElementById('userMsg');

    if (!username) {
        msg.textContent = "请输入用户名";
        return;
    }

    const response = await axios.get("checkUser", { params: { username: username } });

    if (response.data.exist) {
        msg.textContent = "用户名已注册";
        usernameValid = false;
    } else {
        msg.textContent = "用户名可用";
        usernameValid = true;
    }
}

function validForm() {
    if (!usernameValid) {
        alert("请使用未注册的用户名");
        return false;
    }
    return true;
}